public class Rectangle {

    private int width;
    private int height;

    public Rectangle(int width, int height) {
        width  = width;   // bug: should be this.width = width
        height = height;  // bug: should be this.height = height
    }

    public int area() {
        return width * height;
    }

}

public class Main {

    public static void main(String[] args) {
        Rectangle r = new Rectangle(5, 3);
        System.out.println("Area: " + r.area());
    }

}

